    public function testXdrSCMapEntryGettersSetters(): void
    {
        $obj = new XdrSCMapEntry(new XdrSCVal(new XdrSCValType(XdrSCValType::SCV_VOID)), new XdrSCVal(new XdrSCValType(XdrSCValType::SCV_VOID)));
        $this->assertNotNull($obj->getKey());
        $newVal = new XdrSCVal(new XdrSCValType(XdrSCValType::SCV_VOID));
        $obj->setKey($newVal);
